import React from "react";

const HeroServices = () => {
  return (
    <div className="w-full max-w-[1440px] h-auto mx-auto flex flex-col justify-start items-center px-4 sm:px-6">
      {/* Main heading with responsive font sizes */}
      <h1 className="text-[60px] sm:text-[80px] md:text-[100px] lg:text-[120px] xl:text-[170px] text-center font-black uppercase tracking-wider sm:tracking-widest bg-gradient-to-b from-white/15 to-transparent bg-clip-text text-transparent leading-[0.9]">
        Our Services
      </h1>

      {/* Animated button with responsive sizing */}
      <div className="relative h-[25px] sm:h-[28px] md:h-[30px] lg:h-[35px] xl:h-[40px] -mt-8 sm:-mt-10 md:-mt-12 lg:-mt-16 xl:-mt-24 w-[80px] sm:w-[90px] md:w-[100px] lg:w-[130px] xl:w-[150px] rounded-[50px] overflow-hidden bg-neutral-900">
        <div className="glow-effect clockwise"></div>
        <div className="glow-effect counter-clockwise"></div>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-white text-[12px] sm:text-[13px] md:text-[14px] lg:text-[15px] xl:text-[19px] font-black z-10">
            Case Studies
          </span>
        </div>
        <div className="absolute inset-[1.5px] rounded-[48px] bg-black/80 z-0"></div>
      </div>

      {/* Subheadings with responsive font sizes and spacing */}
      <div className="mt-4 sm:mt-5 md:mt-6 text-center">
        <h2 className="text-[20px] sm:text-[24px] md:text-[28px] lg:text-[30px] xl:text-[40px] font-black uppercase tracking-wide sm:tracking-widest bg-white bg-clip-text text-transparent leading-tight">
          Showcasing Our Impact and
        </h2>
        <h2 className="text-[28px] sm:text-[32px] md:text-[36px] lg:text-[40px] xl:text-[50px] -mt-2 sm:-mt-3 md:-mt-4 lg:-mt-5 font-black uppercase tracking-wide sm:tracking-widest bg-gradient-to-r from-lime-400 to-lime-400/20 bg-clip-text text-transparent leading-tight">
          Innovation.
        </h2>
      </div>
    </div>
  );
};

export default HeroServices;
